export async function POST(req: NextRequest) {
  const start = Date.now();
  const client = db();
  let inserted = 0; let errors = 0;
  for (let i = 0; i < TASKS.length; i += 100) {
    const batch = TASKS.slice(i, i+100).map((t:any) => ({id:t.id,roadmap_id:t.roadmap_id??"ECOSYSTEM_v3",phase_id:t.phase_id,title:t.title,description:t.description,depends_on:t.depends_on??[],status:"pending",source:t.source??"canonical_ingestion_v3",updated_at:t.updated_at??Date.now()}) );
    const {error} = await client.from("roadmap_tasks").upsert(batch, {onConflict:"id",ignoreDuplicates:true});
    if (error && error.code !== "23505") { errors++; } else { inserted += batch.length; }
  }
  const {count} = await client.from("roadmap_tasks").select("id",{count:"exact",head:true});
  return NextResponse.json({ok:true,batch:2,inserted,errors,totalNow:count??0,durationMs:Date.now()-start,next:"/api/canonical/ingest-ecosystem-v3-b3"});
}
